import { execSync } from 'child_process';
import fs from 'fs';

try {
  execSync('npx eslint -f json . > lint.json', { encoding: 'utf-8', stdio: 'pipe' });
} catch (e) {}

try {
  execSync('npx vite build', { encoding: 'utf-8', stdio: 'pipe' });
  fs.writeFileSync('build.txt', 'Build succeeded');
} catch (e) {
  fs.writeFileSync('build.txt', (e.stdout || '') + (e.stderr || ''));
}

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.VITE_SUPABASE_URL;
const supabaseKey = process.env.VITE_SUPABASE_ANON_KEY;
const supabase = createClient(supabaseUrl, supabaseKey);

async function checkSchema() {
  const { data, error } = await supabase.from('employee_roles').select('*').limit(1);
  console.log("Roles:", data);

  const { data: emp, error: e2 } = await supabase.from('employees').select('*').limit(1);
  console.log("Employees:", emp);
}

checkSchema();

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useTheme } from './theme/useTheme';
import ThemeToggle from './theme/themeToggle';
import './App.css';

// 1. New Supabase Import
import { supabase } from './services/supabaseClient';
import { masterErrorHandler } from './services/masterErrorHandler';

// Constants
import { VERTICALS } from './constants/verticals';
import { DEFAULT_ROLE_PERMISSIONS, getPermissionsForLevel } from './constants/roles';

// Components
import Sidebar from './components/Sidebar';
import VerticalWorkspace from './components/VerticalWorkspace';
import ExecutiveSummary from './components/ExecutiveSummary';
import Configuration from './components/Configuration';
import UserProfile from './components/UserProfile';
import UserRoleManagement from './components/UserRoleManagement';
import UserManagement from './components/UserManagement';
import HubManagement from './verticals/ChargingHubs/HubManagement';
import HubFunctionManagement from './verticals/ChargingHubs/HubFunctionManagement';
import HubSubSidebar from './verticals/ChargingHubs/HubSubSidebar';
import HubTaskForm from './verticals/ChargingHubs/HubTaskForm';
import HubTaskTile from './verticals/ChargingHubs/HubTaskTile';
import EmployeeSubSidebar from './verticals/Employees/EmployeeSubSidebar';
import EmployeeTaskForm from './verticals/Employees/EmployeeTaskForm';
import EmployeeTaskTile from './verticals/Employees/EmployeeTaskTile';
import EmployeeManagement from './verticals/Employees/EmployeeManagement';
import DepartmentManagement from './verticals/Employees/DepartmentManagement';
import EmployeeRoleManagement from './verticals/Employees/EmployeeRoleManagement';
import Login from './components/Login';

// Assets
import powerLogo from './assets/logo.svg';

/**
 * Supabase stores column names in lowercase.
 * This mapper converts them to the camelCase keys the rest of the app expects.
 */
const normalizeTask = (row) => ({
  id: row.id,
  text: row.text,
  verticalId: row.verticalid ?? row.verticalId,
  stageId: row.stageid ?? row.stageId,
  priority: row.priority,
  description: row.description,
  hub_id: row.hub_id,
  city: row.city,
  function: row.function,
  assigned_to: row.assigned_to,
  assigneeName: row.employees?.full_name || row.assigneeName, // Support joined data or flat data
  createdAt: row.createdat ?? row.createdAt,
  updatedAt: row.updatedat ?? row.updatedAt,
});

function App() {
  const { darkMode, toggleTheme } = useTheme();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeVertical, setActiveVertical] = useState(() => localStorage.getItem('power_project_active_vertical'));


  // src/App.jsx - around line 35
  const fetchTasks = useCallback(async (showLoading = true) => {
    if (showLoading) setLoading(true);

    try {
      const { data, error, status } = await supabase
        .from('tasks')
        .select(`
          *,
          employees:assigned_to (
            full_name
          )
        `)
        .order('updatedat', { ascending: true });

      if (error) {
        masterErrorHandler.handleDatabaseError(error, 'Task Fetch');
      } else {
        setTasks((data || []).map(normalizeTask));
      }
    } catch (err) {
      masterErrorHandler.handleComponentError(err, 'App', 'Task Fetch');
    } finally {
      if (showLoading) setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTasks();
  }, [fetchTasks]);

  // 3. Auth and User Identity
  const [session, setSession] = useState(null);
  const [user, setUser] = useState(null);
  const [profileError, setProfileError] = useState(null);

  const [rolePermissions, setRolePermissions] = useState(() => {
    const saved = localStorage.getItem('power_project_permissions');
    if (!saved) return DEFAULT_ROLE_PERMISSIONS;
    try {
      const parsed = JSON.parse(saved);
      return { ...DEFAULT_ROLE_PERMISSIONS, ...parsed };
    } catch {
      return DEFAULT_ROLE_PERMISSIONS;
    }
  });

  // Persistent UI states
  const [isSidebarOpen, setIsSidebarOpen] = useState(() => localStorage.getItem('sidebar_state') === 'true');
  const [isSubSidebarOpen, setIsSubSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sub_sidebar_state');
    return saved !== null ? saved === 'true' : true;
  });

  // Compute current permissions dynamically based on active vertical
  const currentUserPermissions = useMemo(() => {
    if (!user) return {};

    const roleId = user.roleId;
    const isMasterScope = roleId?.startsWith('master_');

    if (isMasterScope) {
      // Global scope: use the static permissions from the roleId
      return rolePermissions[roleId] || DEFAULT_ROLE_PERMISSIONS[roleId] || DEFAULT_ROLE_PERMISSIONS['vertical_viewer'];
    } else {
      // Vertical scope: look up the specific level for this vertical
      const level = user.verticalPermissions?.[activeVertical] || 'viewer';
      const baseCaps = getPermissionsForLevel(level);

      return {
        ...baseCaps,
        scope: 'assigned',
        canAccessConfig: level === 'admin' // Only 'vertical_admin' level has config access
      };
    }
  }, [user, activeVertical, rolePermissions]);

  // Test database connection on app start
  useEffect(() => {
    masterErrorHandler.testDatabaseConnection();
  }, []);

  // Auth State Listener
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchUserProfile(session.user.id);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) {
        fetchUserProfile(session.user.id);
      } else {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId) => {
    const { data, error } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', userId)
      .single();

    if (error) {
      console.error("Error fetching user profile:", error);
      // If code is PGRST116 (0 rows returned), the trigger may not have fired
      if (error.code === 'PGRST116') {
        setProfileError("User profile not found in database. Did you run the SQL script or sign in before the trigger was added?");
      } else {
        setProfileError(error.message);
      }
    } else if (data) {
      setUser({
        id: data.id,
        name: data.name || "User",
        role: data.role_id,
        roleId: data.role_id,
        assignedVerticals: data.assigned_verticals || ["CHARGING_HUBS"],
        verticalPermissions: data.vertical_permissions || {}
      });
      setProfileError(null);
    }
  };


  /**
   * SECURITY VALIDATION:
   * Ensures the user has permissions for the currently 'activeVertical'.
   * If permissions are revoked in the backend, we force them back to the dashboard.
   */
  useEffect(() => {
    if (!user || !activeVertical) return;

    // Public/Special views logic
    const isMasterAdmin = user.roleId === 'master_admin';
    const isGlobalScope = currentUserPermissions.scope === 'global';
    const isConfigView = ['configuration', 'role_management', 'user_management'].includes(activeVertical);

    // Check if the vertical is strictly assigned OR if they have global scope
    const isSpecialAdminView = ['user_management', 'role_management'].includes(activeVertical);
    const hasSpecialAccess = isMasterAdmin; // Only Master Admin can see these management tools

    // Validate access
    if (isSpecialAdminView && !hasSpecialAccess) {
      setActiveVertical(null);
      return;
    }

    if (activeVertical === 'configuration' && !currentUserPermissions.canAccessConfig) {
      setActiveVertical(null);
      return;
    }

    // Charging Hubs special CRUD view handling
    if (activeVertical === 'hub_management' && !isMasterAdmin) {
      setActiveVertical(null);
      return;
    }

    // Standard Vertical validation
    const verticalKeys = Object.keys(VERTICALS);
    if (verticalKeys.includes(activeVertical)) {
      const isAssigned = user.assignedVerticals?.includes(activeVertical);
      if (!isAssigned && !isGlobalScope) {
        setActiveVertical(null);
      }
    }
  }, [user, activeVertical, currentUserPermissions]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setProfileError(null);
  };

  // Sync Local Preferences
  useEffect(() => { if (user) localStorage.setItem('power_project_user', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('power_project_permissions', JSON.stringify(rolePermissions)); }, [rolePermissions]);
  useEffect(() => { localStorage.setItem('sidebar_state', isSidebarOpen); }, [isSidebarOpen]);
  useEffect(() => { localStorage.setItem('sub_sidebar_state', isSubSidebarOpen); }, [isSubSidebarOpen]);
  useEffect(() => {
    if (activeVertical) {
      // Don't save transient management sub-views as the default vertical
      const persistentVerticals = ['CHARGING_HUBS', 'EMPLOYEES', 'employee_tasks'];
      if (persistentVerticals.includes(activeVertical)) {
        localStorage.setItem('power_project_active_vertical', activeVertical);
      }
    } else {
      localStorage.removeItem('power_project_active_vertical');
    }
  }, [activeVertical]);

  // 4. Supabase CRUD Helpers (Replaces LocalStorage mutation)

  /**
   * Adds a task to the Supabase cloud.
   * Logic: Inserts and then updates local state with the returned DB object (including its new UUID).
   */
  const addTask = async (taskData) => {
    const taskRow = {
      id: taskData.id,
      text: taskData.text,
      verticalid: taskData.verticalId,
      stageid: taskData.stageId,
      priority: taskData.priority || null,
      description: taskData.description || null,
      hub_id: taskData.hub_id === '' ? null : (taskData.hub_id || null),
      city: taskData.city || null,
      function: taskData.function || null,
      assigned_to: taskData.assigned_to || null,
      createdat: taskData.createdAt,
      updatedat: taskData.updatedAt,
    };

    try {
      const { data, error } = await supabase
        .from('tasks')
        .insert([taskRow])
        .select();

      if (error) throw error;
      if (data) {
        setTasks(prev => [...prev, normalizeTask(data[0])]);
      }
    } catch (err) {
      console.error("❌ Cloud Sync Error:", err.message);
      throw err;
    }
  };

  /**
   * Deletes a task from Supabase.
   */
  const deleteTask = async (taskId) => {
    if (window.confirm("Delete this task?")) {
      const { error } = await supabase
        .from('tasks')
        .delete()
        .eq('id', taskId);

      if (error) {
        console.error("Error deleting task:", error.message);
      } else {
        setTasks(prev => prev.filter(t => t.id !== taskId));
      }
    }
  };

  /**
   * Updates a task stage in Supabase.
   */
  const updateTaskStage = async (taskId, newStageId) => {
    const { error } = await supabase
      .from('tasks')
      .update({ stageid: newStageId, updatedat: new Date().toISOString() })
      .eq('id', taskId);

    if (error) {
      console.error("Error updating stage:", error.message);
    } else {
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, stageId: newStageId } : t));
    }
  };

  /**
   * Performs a full update of a task in Supabase.
   */
  const updateTask = async (taskData) => {
    const taskRow = {
      text: taskData.text,
      verticalid: taskData.verticalId,
      stageid: taskData.stageId,
      priority: taskData.priority || null,
      description: taskData.description || null,
      hub_id: taskData.hub_id === '' ? null : (taskData.hub_id || null),
      city: taskData.city || null,
      function: taskData.function || null,
      assigned_to: taskData.assigned_to || null,
      updatedat: new Date().toISOString(),
    };

    try {
      const { data, error } = await supabase
        .from('tasks')
        .update(taskRow)
        .eq('id', taskData.id)
        .select();

      if (error) throw error;
      if (data) {
        setTasks(prev => prev.map(t => t.id === taskData.id ? normalizeTask(data[0]) : t));
      }
    } catch (err) {
      console.error("❌ Task Update Error:", err.message);
      throw err;
    }
  };

  /**
   * Bulk updates multiple tasks in Supabase.
   * Useful for "Clear Board" operations.
   */
  const bulkUpdateTasks = async (taskIds, updates) => {
    try {
      const { data, error } = await supabase
        .from('tasks')
        .update({ ...updates, updatedat: new Date().toISOString() })
        .in('id', taskIds)
        .select();

      if (error) throw error;

      if (data) {
        const normalized = data.map(normalizeTask);
        setTasks(prev => prev.map(t => {
          const updated = normalized.find(n => n.id === t.id);
          return updated || t;
        }));
      }
    } catch (err) {
      console.error("❌ Bulk Update Error:", err.message);
      throw err;
    }
  };

  // Loading Screen for initial fetch
  if (loading) {
    return (
      <div className="loading-screen" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <h2>Connecting to Cloud Database...</h2>
      </div>
    );
  }

  if (!session) {
    return (
      <div className="app-container" data-theme={darkMode ? 'dark' : 'light'}>
        <Login />
      </div>
    );
  }

  if (!user) {
    return (
      <div className="app-container" data-theme={darkMode ? 'dark' : 'light'}>
        <div className="loading-screen" style={{ display: 'flex', flexDirection: 'column', gap: '1rem', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
          {profileError ? (
            <>
              <h2 style={{ color: '#ff4444' }}>Profile Error</h2>
              <p style={{ maxWidth: '400px', textAlign: 'center' }}>{profileError}</p>
              <button
                onClick={handleLogout}
                style={{ marginTop: '1rem', padding: '10px 20px', backgroundColor: 'var(--brand-green)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}
              >
                Sign Out & Try Again
              </button>
            </>
          ) : (
            <h2>Loading User Profile...</h2>
          )}
        </div>
      </div>
    );
  }


  return (
    <div className="app-container" data-theme={darkMode ? 'dark' : 'light'}>
      <div className="app-layout">
        <button className="logo-button" onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          <img src={powerLogo} alt="Logo" className="logo-svg" />
        </button>
        <Sidebar
          isOpen={isSidebarOpen}
          onClose={() => setIsSidebarOpen(false)}
          setActiveVertical={setActiveVertical}
          activeVertical={activeVertical}
          user={user}
          permissions={currentUserPermissions}
        />
        <div className={`app-main-area ${activeVertical ? 'no-padding' : ''}`}>
          <header className="app-header">
            <div className="header-left">
              {/* Spacer for absolute logo */}
            </div>
            <div className="header-center"><h1 className="brand-title">PowerProject</h1></div>
            <div className="header-right">
              {user?.roleId === 'master_admin' && (
                <ThemeToggle darkMode={darkMode} toggleTheme={toggleTheme} />
              )}
              <div style={{ width: '16px' }} />
              <UserProfile user={user} onConfigClick={() => setActiveVertical('configuration')} onLogout={handleLogout} />
            </div>
          </header>
          <main className="app-content">
            {!activeVertical ? (
              <ExecutiveSummary tasks={tasks} user={user} permissions={currentUserPermissions} />
            ) : activeVertical === 'configuration' ? (
              <Configuration tasks={tasks} setTasks={setTasks} user={user} permissions={currentUserPermissions} setActiveVertical={setActiveVertical} />
            ) : activeVertical === 'role_management' ? (
              <UserRoleManagement permissions={rolePermissions} setPermissions={setRolePermissions} onBack={() => setActiveVertical('configuration')} />
            ) : activeVertical === 'user_management' ? (
              <UserManagement currentUser={user} />
            ) : activeVertical === 'hub_management' ? (
              <HubManagement />
            ) : activeVertical === 'hub_function_management' ? (
              <HubFunctionManagement />
            ) : activeVertical === 'department_management' ? (
              <DepartmentManagement />
            ) : activeVertical === 'employee_role_management' ? (
              <EmployeeRoleManagement />
            ) : (
              <VerticalWorkspace
                label={(activeVertical === 'EMPLOYEES' || activeVertical === 'employee_tasks') ? "Employees" : VERTICALS[activeVertical]?.label}
                activeVertical={activeVertical}
                tasks={tasks}
                setTasks={addTask}
                actualSetTasks={setTasks} // Pass raw setter for local updates
                refreshTasks={fetchTasks}
                updateTask={updateTask}
                bulkUpdateTasks={bulkUpdateTasks}
                deleteTask={deleteTask}
                updateTaskStage={updateTaskStage}
                isSubSidebarOpen={isSubSidebarOpen}
                setIsSubSidebarOpen={setIsSubSidebarOpen}
                setActiveVertical={setActiveVertical}
                SidebarComponent={
                  activeVertical === 'CHARGING_HUBS' ? HubSubSidebar :
                    (activeVertical === 'EMPLOYEES' || activeVertical === 'employee_tasks') ? EmployeeSubSidebar :
                      null
                }
                TaskFormComponent={
                  activeVertical === 'CHARGING_HUBS' ? HubTaskForm :
                    (activeVertical === 'EMPLOYEES' || activeVertical === 'employee_tasks') ? EmployeeTaskForm :
                      null
                }
                TaskTileComponent={
                  activeVertical === 'CHARGING_HUBS' ? HubTaskTile :
                    (activeVertical === 'EMPLOYEES' || activeVertical === 'employee_tasks') ? EmployeeTaskTile :
                      null
                }
                onHeaderClick={
                  (activeVertical === 'employee_tasks')
                    ? () => setActiveVertical('EMPLOYEES')
                    : (user?.roleId === 'master_admin' && activeVertical === 'CHARGING_HUBS')
                      ? () => setActiveVertical('hub_management')
                      : null
                }
                user={user}
                permissions={currentUserPermissions}
              >
                {activeVertical === 'EMPLOYEES' && (
                  <EmployeeManagement
                    user={user}
                    permissions={currentUserPermissions}
                    tasks={tasks.filter(t => t.verticalId === 'EMPLOYEES')}
                  />
                )}
              </VerticalWorkspace>
            )}

          </main>
        </div>
      </div>
    </div>
  );
}

export default App;

import React, { useRef, useState } from 'react';
import Papa from 'papaparse';
import ExcelJS from 'exceljs';
import CSVConflictModal from './ConflictModal';
import './CSVImportButton.css';

/**
 * CSVImportButton — Master Import Orchestrator
 *
 * Handles the full import lifecycle:
 *   1. File parsing (CSV or XLSX)
 *   2. Required field validation
 *   3. In-file duplicate detection (via getConflictKey)
 *   4. Database conflict detection (via existingData + getConflictKey)
 *   5. Conflict resolution modal (CSVConflictModal)
 *   6. Calls onDataParsed with the final clean, resolved set of rows
 *
 * Props:
 *   onDataParsed      {function}  - Called with (resolvedRows, stats) after all conflicts are resolved
 *   requiredFields    {string[]}  - Fields that must be non-empty for a row to be valid
 *   getConflictKey    {function}  - (row) => string. Defines row uniqueness for dedup
 *   existingData      {object[]}  - Current DB records for conflict comparison
 *   renderConflictTile {function} - (conflict, isSelected) => JSX for modal tiles
 *   entityName        {string}    - Used in modal labels (e.g. "Tasks", "Employees")
 *   label             {string}    - Button label text
 *   className         {string}    - Extra CSS class names
 *   accept            {string}    - Accepted file extensions (default: .csv,.xlsx)
 *   disabled          {boolean}   - Disables the button
 */
const CSVImportButton = ({
  onDataParsed,
  requiredFields = [],
  getConflictKey = null,
  existingData = null,
  renderConflictTile = null,
  entityName = 'Entries',
  label = 'Import CSV',
  className = '',
  accept = '.csv,.xlsx',
  disabled = false,
  onFocus = null,
  compareFields = [],
  findConflict = null // (row, existingData) => { csvRow, existingRecord, matchMode } | null
}) => {
  const inputRef = useRef(null);
  const [status, setStatus] = useState(null); // null | 'success' | 'error'
  const [showConflicts, setShowConflicts] = useState(false);
  const [pendingConflicts, setPendingConflicts] = useState({ conflicts: [], nonConflictingRows: [] });

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setStatus(null);

    const isExcel = file.name.endsWith('.xlsx');

    if (isExcel) {
      const reader = new FileReader();
      reader.onload = async (evt) => {
        try {
          const buffer = evt.target.result;
          const workbook = new ExcelJS.Workbook();
          await workbook.xlsx.load(buffer);
          const worksheet = workbook.worksheets[0];
          const rows = [];
          const headerRow = worksheet.getRow(1);
          const headers = [];
          headerRow.eachCell((cell, colNumber) => {
            headers[colNumber] = cell.text.trim().toLowerCase();
          });
          worksheet.eachRow((row, rowNumber) => {
            if (rowNumber === 1) return;
            const rowData = {};
            row.eachCell((cell, colNumber) => {
              const header = headers[colNumber];
              if (header) rowData[header] = cell.text;
            });
            rows.push(rowData);
          });
          processRows(rows);
        } catch (err) {
          console.error('Excel Parsing Error:', err);
          setStatus('error');
        }
      };
      reader.readAsArrayBuffer(file);
    } else {
      Papa.parse(file, {
        header: true,
        skipEmptyLines: true,
        transformHeader: (h) => h.trim().toLowerCase(),
        complete: (result) => processRows(result.data),
        error: () => setStatus('error'),
      });
    }

    // Reset so the same file can be re-uploaded
    e.target.value = '';
  };

  const normalizeHeaders = (data) => {
    if (!data || data.length === 0) return data;

    // Default system-wide mapping (can be extended via props)
    const defaultMap = {
      full_name: ['full_name', 'name', 'full name', 'employee name', 'staff name', 'fullname', 'emp name'],
      email: ['email', 'email address', 'emailid', 'email_id', 'mail'],
      phone: ['phone', 'contact', 'mobile', 'phone number', 'contact number', 'contactnumber', 'phone_number'],
      dept_code: ['department', 'dept', 'city', 'location', 'unit', 'department_code', 'department_name'],
      role_code: ['role', 'designation', 'position', 'role_code', 'job title', 'role_id', 'role_name'],
      hire_date: ['hire_date', 'doj', 'joining date', 'hire date', 'joining_date', 'date of joining', 'dateofjoining'],
      status: ['status', 'active', 'state'],
      gender: ['gender', 'sex', 'male/female'],
      dob: ['dob', 'date of birth', 'birth date', 'birthdate'],
      hub_code: ['hub_code', 'primary hub', 'hub', 'location code', 'station'],
      account_number: ['account_number', 'account number', 'bank account', 'acc num'],
      ifsc_code: ['ifsc_code', 'ifsc code', 'ifsc'],
      account_name: ['account_name', 'account name', 'bank name', 'beneficiary'],
      pan_number: ['pan_number', 'pan number', 'pan', 'pan no', 'pan card']
    };

    return data.map(row => {
      const normalized = {};
      Object.keys(row).forEach(key => {
        const lowerKey = key.toLowerCase().trim().replace(/_/g, '').replace(/\s/g, '');
        const canonicalKey = Object.keys(defaultMap).find(ck => 
          defaultMap[ck].some(alias => {
            const normAlias = alias.toLowerCase().replace(/_/g, '').replace(/\s/g, '');
            return normAlias === lowerKey;
          })
        );
        if (canonicalKey) {
          normalized[canonicalKey] = row[key];
        } else {
          normalized[key] = row[key];
        }
      });
      return normalized;
    });
  };

  const processRows = (rawRows) => {
    // 0. Robust Header Normalization
    const rows = normalizeHeaders(rawRows);

    // 1. Required field validation
    let skipped = 0;
    const valid = rows.filter((row) => {
      const isValid = requiredFields.every(
        (field) => row[field] && String(row[field]).trim() !== ''
      );
      if (!isValid) skipped++;
      return isValid;
    });

    if (valid.length === 0) {
      console.warn('All rows failed required field check:', requiredFields);
      setStatus('error');
      return;
    }

    // 2. In-file deduplication (last occurrence wins)
    let inFileDups = 0;
    let dedupedRows = valid;
    if (getConflictKey) {
      const seen = new Map();
      valid.forEach(row => seen.set(getConflictKey(row), row));
      dedupedRows = Array.from(seen.values());
      inFileDups = valid.length - dedupedRows.length;
    }

    // 3. Database conflict detection
    if (existingData && (findConflict || getConflictKey)) {
      const conflicts = [];
      const nonConflictingRows = [];

      if (findConflict) {
        dedupedRows.forEach(row => {
          const conflict = findConflict(row, existingData);
          if (conflict) {
            conflicts.push({ ...conflict, csvRow: row }); // Ensure csvRow is attached
          } else {
            nonConflictingRows.push(row);
          }
        });
      } else {
        const existingMap = new Map(existingData.map(r => [getConflictKey(r), r]));
        dedupedRows.forEach(row => {
          const existingRecord = existingMap.get(getConflictKey(row));
          if (existingRecord) {
            conflicts.push({ csvRow: row, existingRecord });
          } else {
            nonConflictingRows.push(row);
          }
        });
      }

      if (conflicts.length > 0) {
        setPendingConflicts({ conflicts, nonConflictingRows });
        setShowConflicts(true);
        setStatus('success');
        return;
      }
      onDataParsed(nonConflictingRows);
    } else {
      onDataParsed(dedupedRows);
    }
  };

  const handleResolveConflicts = (selectedRowsToUpdate) => {
    setShowConflicts(false);
    // CRITICAL: Extract the actual row data (csvRow) from the conflict objects
    const resolvedData = selectedRowsToUpdate.map(c => c.csvRow);
    const finalRows = [...pendingConflicts.nonConflictingRows, ...resolvedData];
    finalize(finalRows, { skipped: 0, inFileDups: 0 });
  };

  const handleKeepBoth = (conflictToKeep) => {
    // Remove it from the current conflicts array
    const updatedConflicts = pendingConflicts.conflicts.filter(c => c !== conflictToKeep);

    // Add it to the non-conflicting array (it will be inserted as a new row)
    const updatedNonConflicting = [...pendingConflicts.nonConflictingRows, conflictToKeep.csvRow];

    setPendingConflicts({ conflicts: updatedConflicts, nonConflictingRows: updatedNonConflicting });

    // If we've resolved all conflicts this way, finalize automatically
    if (updatedConflicts.length === 0) {
      setShowConflicts(false);
      finalize(updatedNonConflicting, { skipped: 0, inFileDups: 0 });
    }
  };

  const handleCancelConflicts = () => {
    setShowConflicts(false);
    setStatus(null);
  };

  const finalize = (rows, stats) => {
    if (rows.length === 0) {
      setStatus('error');
      return;
    }
    setStatus('success');
    onDataParsed?.(rows, stats);
  };

  return (
    <>
      <div className="csv-import-wrapper">
        <input
          ref={inputRef}
          type="file"
          accept={accept}
          style={{ display: 'none' }}
          onChange={handleFileChange}
          disabled={disabled}
        />
        <button
          className={`halo-button csv-import-btn ${className} ${status === 'error' ? 'import-error' : status === 'success' ? 'import-success' : ''}`}
          onClick={() => inputRef.current?.click()}
          onFocus={onFocus}
          onMouseEnter={onFocus} // Also trigger on hover for faster loading
          title="Import a filled CSV or Excel file"
          disabled={disabled}
        >
          {status === 'error' ? 'Import Failed' : status === 'success' ? 'Imported!' : label}
        </button>
      </div>

      {showConflicts && renderConflictTile && (
        <CSVConflictModal
          isOpen={showConflicts}
          onClose={handleCancelConflicts}
          entityName={entityName}
          conflicts={pendingConflicts.conflicts}
          onResolve={handleResolveConflicts}
          onKeepBoth={handleKeepBoth}
          renderConflictTile={(c) => renderConflictTile(c)}
          compareFields={compareFields}
        />
      )}
    </>
  );
};

