import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import './HubFunctionManagement.css';
import FunctionCSVDownload from './FunctionCSVDownload';
import FunctionCSVImport from './FunctionCSVImport';
import MasterPageHeader from '../../components/MasterPageHeader';

const HubFunctionManagement = () => {
  const [functions, setFunctions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFunction, setEditingFunction] = useState(null);
  const [formData, setFormData] = useState({ name: '', function_code: '', description: '' });
  const [statusMsg, setStatusMsg] = useState({ type: '', text: '' });
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchFunctions();
  }, []);

  const fetchFunctions = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('hub_functions')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error('Error fetching functions:', error);
    } else {
      setFunctions(data || []);
    }
    setLoading(false);
  };

  const handleOpenModal = (fn = null) => {
    if (fn) {
      setEditingFunction(fn);
      setFormData({ 
        name: fn.name, 
        function_code: fn.function_code || '',
        description: fn.description || ''
      });
    } else {
      setEditingFunction(null);
      setFormData({ name: '', function_code: '', description: '' });
    }
    setIsModalOpen(true);
    setStatusMsg({ type: '', text: '' });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatusMsg({ type: '', text: '' });

    const functionData = {
      ...formData,
      updated_at: new Date().toISOString()
    };

    let error;
    if (editingFunction) {
      const { error: updateError } = await supabase
        .from('hub_functions')
        .update(functionData)
        .eq('id', editingFunction.id);
      error = updateError;
    } else {
      const { error: insertError } = await supabase
        .from('hub_functions')
        .insert([functionData]);
      error = insertError;
    }

    if (error) {
      setStatusMsg({ type: 'error', text: `Error: ${error.message}` });
    } else {
      setStatusMsg({ type: 'success', text: `Function ${editingFunction ? 'updated' : 'created'} successfully!` });
      setTimeout(() => {
        setIsModalOpen(false);
        fetchFunctions();
      }, 1000);
    }
    setLoading(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this functional category?')) return;

    setLoading(true);
    const { error } = await supabase.from('hub_functions').delete().eq('id', id);

    if (error) {
      alert(`Delete failed: ${error.message}`);
    } else {
      fetchFunctions();
    }
    setLoading(false);
  };

  return (
    <div className="management-view-container">
      <MasterPageHeader
        title="Hub Function Management"
        description="Define and manage functional categories for charging hub tasks."
        leftActions={
          <div className="view-mode-toggle">
            <button 
              className={`view-toggle-btn ${viewMode === 'grid' ? 'active' : ''}`}
              onClick={() => setViewMode('grid')}
            >
              Grid
            </button>
            <button 
              className={`view-toggle-btn ${viewMode === 'list' ? 'active' : ''}`}
              onClick={() => setViewMode('list')}
            >
              List
            </button>
          </div>
        }
        rightActions={
          <>
            <FunctionCSVDownload 
              className="halo-button master-action-btn" 
              data={functions} 
              label="Export Functions" 
              filename={`hub_functions_export_${new Date().toISOString().split('T')[0]}.csv`}
            />
            <FunctionCSVDownload className="halo-button master-action-btn" label="Download Template" />
            <FunctionCSVImport className="master-action-btn" label="Import Functions" onImportComplete={fetchFunctions} />
            <button className="halo-button master-action-btn" onClick={() => handleOpenModal()}>
              + New Function
            </button>
          </>
        }
      />

      {loading && !isModalOpen && <div className="loading-spinner">Loading Functions...</div>}

      {viewMode === 'grid' ? (
        <div className="hubs-grid">
          {functions.map(fn => (
            <div key={fn.id} className="hub-card">
              <div className="hub-code-tag">{fn.function_code || 'NO CODE'}</div>
              <h3>{fn.name}</h3>
              <p className="hub-city">{fn.description || 'No description provided'}</p>
              <div className="hub-actions">
                <button className="halo-button edit-btn" onClick={() => handleOpenModal(fn)}>Edit</button>
                <button className="halo-button delete-btn" onClick={() => handleDelete(fn.id)}>Delete</button>
              </div>
            </div>
          ))}
          {functions.length === 0 && !loading && (
            <div className="empty-state">
              <p>No functional categories found. Create your first function to get started!</p>
            </div>
          )}
        </div>
      ) : (
        <div className="hubs-list-view">
          <table className="management-table">
            <thead>
              <tr>
                <th>Function Name</th>
                <th>Code</th>
                <th>Description</th>
                <th style={{ textAlign: 'right' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {functions.map(fn => (
                <tr key={fn.id}>
                  <td className="name-cell">{fn.name}</td>
                  <td><code className="code-font">{fn.function_code || '—'}</code></td>
                  <td style={{ opacity: 0.7, fontSize: '0.85rem' }}>{fn.description || '—'}</td>
                  <td style={{ textAlign: 'right' }}>
                    <div className="table-actions">
                      <button className="icon-btn edit" onClick={() => handleOpenModal(fn)} title="Edit">✎</button>
                      <button className="icon-btn delete" onClick={() => handleDelete(fn.id)} title="Delete">×</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {functions.length === 0 && !loading && (
            <div className="empty-state">
              <p>No functions found.</p>
            </div>
          )}
        </div>
      )}

      {isModalOpen && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="modal-content hub-modal" onClick={(e) => e.stopPropagation()}>
            <header className="modal-header">
              <h2>{editingFunction ? 'Edit Hub Function' : 'Create New Function'}</h2>
              <button className="close-modal" onClick={() => setIsModalOpen(false)}>&times;</button>
            </header>

            <form onSubmit={handleSubmit} className="vertical-task-form">
              <div className="form-row-grid">
                <div className="form-group">
                  <label>Function Name</label>
                  <input 
                    type="text" 
                    value={formData.name} 
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Maintenance, Inspection, Cleaning"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Function Code (Short ID)</label>
                  <input 
                    type="text" 
                    value={formData.function_code} 
                    onChange={(e) => setFormData({...formData, function_code: e.target.value})}
                    placeholder="e.g. MNT, CLN, INSP"
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea 
                  value={formData.description} 
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="What does this function involve?"
                  rows={4}
                />
              </div>

              {statusMsg.text && (
                <div className={`status-message ${statusMsg.type}`}>
                  {statusMsg.text}
                </div>
              )}

              <div className="modal-footer">
                <button type="button" className="halo-button cancel-btn" onClick={() => setIsModalOpen(false)}>Cancel</button>
                <button type="submit" className="halo-button save-btn" disabled={loading}>
                  {loading ? 'Saving...' : (editingFunction ? 'Update' : 'Create')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HubFunctionManagement;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';

/**
 * HubSubSidebar
 * 
 * Vertical-specific sidebar content for Charging Hubs.
 * Contains the Master Admin administrative shortcut and task filters.
 */
const HubSubSidebar = ({ user, permissions, activeVertical, setActiveVertical, onFilterChange, onReset, onBatchFilter, filters, tasks }) => {
  const canAccessAdmin = permissions?.canAccessConfig;
  const [hubs, setHubs] = useState([]);
  const [functions, setFunctions] = useState([]);
  const [expandedGroups, setExpandedGroups] = useState({
    city: false,
    hub: false,
    priority: false,
    function: false
  });

  useEffect(() => {
    const fetchData = async () => {
      const { data: hubData } = await supabase.from('hubs').select('id, hub_code');
      const { data: funcData } = await supabase.from('hub_functions').select('id, function_code, name');
      if (hubData) setHubs(hubData);
      if (funcData) setFunctions(funcData);
    };
    fetchData();
  }, []);

  const cities = [...new Set((tasks || []).map(t => t.city).filter(Boolean))].sort();
  const priorities = ['Low', 'Medium', 'High', 'Urgent'];

  const toggleGroup = (key) => {
    setExpandedGroups(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const selectAll = (key, options, valueKey) => {
    options.forEach(opt => {
      const val = valueKey ? opt[valueKey] : opt;
      if (!filters[key]?.includes(val)) {
        onFilterChange(key, val);
      }
    });
  };

  const filterSectionStyle = {
    borderBottom: '1px solid var(--border-color)',
    transition: 'all 0.3s ease'
  };

  const groupHeaderStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '12px',
    cursor: 'pointer',
    userSelect: 'none'
  };

  const groupLabelStyle = {
    fontSize: '0.75rem',
    fontWeight: 600,
    textTransform: 'uppercase',
    color: 'var(--brand-green)',
    letterSpacing: '0.5px'
  };

  const checkboxGroupStyle = (isExpanded) => ({
    display: isExpanded ? 'flex' : 'none',
    flexDirection: 'column',
    gap: '8px',
    maxHeight: '180px',
    overflowY: 'auto',
    padding: '0 12px 16px 12px',
    transition: 'opacity 0.2s ease'
  });

  const checkboxItemStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    cursor: 'pointer',
    fontSize: '0.85rem',
    color: 'var(--text-color)',
    padding: '4px 0',
    opacity: 0.8
  };

  const checkMarkStyle = (isSelected) => ({
    width: '16px',
    height: '16px',
    borderRadius: '4px',
    border: '2px solid var(--border-color)',
    backgroundColor: isSelected ? 'var(--brand-green)' : 'transparent',
    borderColor: isSelected ? 'var(--brand-green)' : 'var(--border-color)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '10px',
    color: 'white',
    transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)'
  });

  const FilterGroup = ({ label, options, currentFilters, filterKey, displayKey, valueKey }) => {
    const isExpanded = expandedGroups[filterKey];
    return (
      <div style={filterSectionStyle}>
        <div style={groupHeaderStyle} onClick={() => toggleGroup(filterKey)}>
          <span style={groupLabelStyle}>{label}</span>
          <span style={{ fontSize: '0.7rem', opacity: 0.5 }}>{isExpanded ? '▲' : '▼'}</span>
        </div>

        {isExpanded && (
          <div style={{ padding: '0 12px 8px 12px', display: 'flex', gap: '12px' }}>
            <button 
              onClick={(e) => { 
                e.stopPropagation(); 
                const allVals = options.map(opt => valueKey ? opt[valueKey] : opt);
                onBatchFilter(filterKey, allVals); 
              }}
              className="text-action-button"
              style={{ fontSize: '0.65rem', fontWeight: 600, color: 'var(--brand-green)', background: 'none', border: 'none', padding: 0, cursor: 'pointer', opacity: 0.8 }}
            >
              SELECT ALL
            </button>
            <button 
              onClick={(e) => { 
                e.stopPropagation(); 
                onBatchFilter(filterKey, []); 
              }}
              className="text-action-button"
              style={{ fontSize: '0.65rem', fontWeight: 600, color: '#ef4444', background: 'none', border: 'none', padding: 0, cursor: 'pointer', opacity: 0.8 }}
            >
              CLEAR
            </button>
          </div>
        )}

        <div style={checkboxGroupStyle(isExpanded)} className="custom-scrollbar">
          {options.map(opt => {
            const val = valueKey ? opt[valueKey] : opt;
            const labelText = displayKey ? opt[displayKey] : opt;
            const isSelected = currentFilters.includes(val);
            return (
              <div 
                key={val} 
                style={{ ...checkboxItemStyle, opacity: isSelected ? 1 : 0.6 }}
                onClick={() => onFilterChange(filterKey, val)}
              >
                <div style={checkMarkStyle(isSelected)}>
                  {isSelected && '✓'}
                </div>
                <span style={{ fontWeight: isSelected ? 600 : 400 }}>{labelText}</span>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="sub-sidebar-body">
      {canAccessAdmin && (
        <div style={{ padding: '12px', marginBottom: '8px' }}>
          <button 
            className="halo-button" 
            style={{ width: '100%' }}
            onClick={() => setActiveVertical('hub_function_management')}
          >
            Function Manager
          </button>
        </div>
      )}

      <div style={{ padding: '8px 12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid var(--border-color)' }}>
        <p style={{ margin: 0, fontWeight: 700, fontSize: '0.9rem', color: 'var(--text-color)' }}>FILTERS</p>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={() => onFilterChange('duplicatesOnly', !filters.duplicatesOnly)}
            style={{ 
              background: 'none', 
              border: 'none', 
              color: 'var(--brand-green)', 
              fontSize: '0.7rem', 
              fontWeight: 800, 
              cursor: 'pointer',
              padding: '4px',
              opacity: filters.duplicatesOnly ? 1 : 0.5,
              textDecoration: filters.duplicatesOnly ? 'underline' : 'none'
            }}
          >
            DUP ONLY
          </button>
          <button 
            onClick={onReset}
            style={{ 
              background: 'none', 
              border: 'none', 
              color: 'var(--brand-green)', 
              fontSize: '0.7rem', 
              fontWeight: 800, 
              cursor: 'pointer',
              padding: '4px'
            }}
          >
            RESET
          </button>
        </div>
      </div>

      <FilterGroup 
        label="City" 
        options={cities} 
        currentFilters={filters.city || []} 
        filterKey="city" 
      />

      <FilterGroup 
        label="Hub" 
        options={hubs} 
        currentFilters={filters.hub || []} 
        filterKey="hub" 
        displayKey="hub_code"
        valueKey="id"
      />

      <FilterGroup 
        label="Priority" 
        options={priorities} 
        currentFilters={filters.priority || []} 
        filterKey="priority" 
      />

      <FilterGroup 
        label="Function" 
        options={functions} 
        currentFilters={filters.function || []} 
        filterKey="function" 
        displayKey="function_code"
        valueKey="name"
      />

      <div className="sub-nav-item" style={{ marginTop: '24px', opacity: 0.4 }}>
        <div className="sub-nav-text">
          <p>Module Navigation</p>
          <small>Vertical Active</small>
        </div>
      </div>
    </div>
  );
};

export default HubSubSidebar;

