import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import '../ChargingHubs/HubFunctionManagement.css'; // Reuse styles
import MasterPageHeader from '../../components/MasterPageHeader';

const DepartmentManagement = () => {
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDept, setEditingDept] = useState(null);
  const [formData, setFormData] = useState({ name: '', dept_code: '', description: '' });
  const [statusMsg, setStatusMsg] = useState({ type: '', text: '' });
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchDepartments();
  }, []);

  const fetchDepartments = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('departments')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error('Error fetching departments:', error);
    } else {
      setDepartments(data || []);
    }
    setLoading(false);
  };

  const handleOpenModal = (dept = null) => {
    if (dept) {
      setEditingDept(dept);
      setFormData({ 
        name: dept.name, 
        dept_code: dept.dept_code || '',
        description: dept.description || ''
      });
    } else {
      setEditingDept(null);
      setFormData({ name: '', dept_code: '', description: '' });
    }
    setIsModalOpen(true);
    setStatusMsg({ type: '', text: '' });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatusMsg({ type: '', text: '' });

    const deptData = {
      ...formData,
      updated_at: new Date().toISOString()
    };

    let error;
    if (editingDept) {
      const { error: updateError } = await supabase
        .from('departments')
        .update(deptData)
        .eq('id', editingDept.id);
      error = updateError;
    } else {
      const { error: insertError } = await supabase
        .from('departments')
        .insert([deptData]);
      error = insertError;
    }

    if (error) {
      setStatusMsg({ type: 'error', text: `Error: ${error.message}` });
    } else {
      setStatusMsg({ type: 'success', text: `Department ${editingDept ? 'updated' : 'created'} successfully!` });
      setTimeout(() => {
        setIsModalOpen(false);
        fetchDepartments();
      }, 1000);
    }
    setLoading(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this department?')) return;

    setLoading(true);
    const { error } = await supabase.from('departments').delete().eq('id', id);

    if (error) {
      alert(`Delete failed: ${error.message}`);
    } else {
      fetchDepartments();
    }
    setLoading(false);
  };

  return (
    <div className="management-view-container">
      <MasterPageHeader
        title="Department Management"
        description="Define and manage organization departments for employee tracking."
        leftActions={
          <div className="view-mode-toggle">
            <button 
              className={`view-toggle-btn ${viewMode === 'grid' ? 'active' : ''}`}
              onClick={() => setViewMode('grid')}
            >
              Grid
            </button>
            <button 
              className={`view-toggle-btn ${viewMode === 'list' ? 'active' : ''}`}
              onClick={() => setViewMode('list')}
            >
              List
            </button>
          </div>
        }
        rightActions={
          <button className="halo-button master-action-btn" onClick={() => handleOpenModal()}>
            + New Department
          </button>
        }
      />

      {loading && !isModalOpen && <div className="loading-spinner">Loading Departments...</div>}

      {viewMode === 'grid' ? (
        <div className="hubs-grid">
          {departments.map(dept => (
            <div key={dept.id} className="hub-card">
              <div className="hub-code-tag">{dept.dept_code || 'NO CODE'}</div>
              <h3>{dept.name}</h3>
              <p className="hub-city">{dept.description || 'No description provided'}</p>
              <div className="hub-actions">
                <button className="halo-button edit-btn" onClick={() => handleOpenModal(dept)}>Edit</button>
                <button className="halo-button delete-btn" onClick={() => handleDelete(dept.id)}>Delete</button>
              </div>
            </div>
          ))}
          {departments.length === 0 && !loading && (
            <div className="empty-state">
              <p>No departments found. Create your first department to get started!</p>
            </div>
          )}
        </div>
      ) : (
        <div className="hubs-list-view">
          <table className="management-table">
            <thead>
              <tr>
                <th>Department Name</th>
                <th>Code</th>
                <th>Description</th>
                <th style={{ textAlign: 'right' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {departments.map(dept => (
                <tr key={dept.id}>
                  <td className="name-cell">{dept.name}</td>
                  <td><code className="code-font">{dept.dept_code || '—'}</code></td>
                  <td style={{ opacity: 0.7, fontSize: '0.85rem' }}>{dept.description || '—'}</td>
                  <td style={{ textAlign: 'right' }}>
                    <div className="table-actions">
                      <button className="icon-btn edit" onClick={() => handleOpenModal(dept)} title="Edit">✎</button>
                      <button className="icon-btn delete" onClick={() => handleDelete(dept.id)} title="Delete">×</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {departments.length === 0 && !loading && (
            <div className="empty-state">
              <p>No departments found.</p>
            </div>
          )}
        </div>
      )}

      {isModalOpen && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="modal-content hub-modal" onClick={(e) => e.stopPropagation()}>
            <header className="modal-header">
              <h2>{editingDept ? 'Edit Department' : 'Create New Department'}</h2>
              <button className="close-modal" onClick={() => setIsModalOpen(false)}>&times;</button>
            </header>

            <form onSubmit={handleSubmit} className="vertical-task-form">
              <div className="form-row-grid">
                <div className="form-group">
                  <label>Department Name</label>
                  <input 
                    type="text" 
                    value={formData.name} 
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Engineering, Marketing, Operations"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Department Code</label>
                  <input 
                    type="text" 
                    value={formData.dept_code} 
                    onChange={(e) => setFormData({...formData, dept_code: e.target.value})}
                    placeholder="e.g. ENG, MKT, OPS"
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea 
                  value={formData.description} 
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="What is this department responsible for?"
                  rows={4}
                />
              </div>

              {statusMsg.text && (
                <div className={`status-message ${statusMsg.type}`}>
                  {statusMsg.text}
                </div>
              )}

              <div className="modal-footer">
                <button type="button" className="halo-button cancel-btn" onClick={() => setIsModalOpen(false)}>Cancel</button>
                <button type="submit" className="halo-button save-btn" disabled={loading}>
                  {loading ? 'Saving...' : (editingDept ? 'Update' : 'Create')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DepartmentManagement;

import React from 'react';
import CSVImportButton from '../../components/CSVImportButton';
import { supabase } from '../../services/supabaseClient';
import { normalizeValue, calculateSimilarity } from '../../utils/matchingAlgorithms';
import { generateEmpCode, calculateBadgeId, logEmployeeHistory } from '../../utils/employeeUtils';

/**
 * EmployeeCSVImport — Thin Wrapper
 *
 * Defines employee-specific import rules:
 *   - Conflict key: email address (case-insensitive)
 *   - Resolves dept/role codes to IDs before upsert
 *
 * All duplicate detection (in-file + DB) is handled by CSVImportButton.
 */
const EmployeeCSVImport = ({ onImportComplete, className, label = 'Import CSV' }) => {
  const [importing, setImporting] = React.useState(false);
  const [existingEmps, setExistingEmps] = React.useState(null);
  const [lookupMaps, setLookupMaps] = React.useState(null);

  const loadContext = async () => {
    if (existingEmps && lookupMaps) return { existingEmps, ...lookupMaps };
    const [{ data: depts }, { data: roles }, { data: hubs }, { data: emps }] = await Promise.all([
      supabase.from('departments').select('id, name, dept_code'),
      supabase.from('employee_roles').select('id, name, role_code'),
      supabase.from('hubs').select('id, name, hub_code'),
      supabase.from('employees').select('id, email, full_name, phone, emp_code, badge_id'),
    ]);

    // Robust Mapping: Support both Names and Codes
    const createMap = (items, codeKey) => {
      const m = {};
      items?.forEach(item => {
        if (item.id) {
          const nameKey = item.name?.toLowerCase().trim();
          const codeK = item[codeKey]?.toLowerCase().trim();
          if (nameKey) m[nameKey] = item.id;
          if (codeK) m[codeK] = item.id;
        }
      });
      return m;
    };

    const maps = {
      deptMap: createMap(depts, 'dept_code'),
      roleMap: createMap(roles, 'role_code'),
      hubMap: createMap(hubs, 'hub_code')
    };

    setExistingEmps(emps || []);
    setLookupMaps(maps);
    return { existingEmps: emps || [], ...maps };
  };
  // Pre-load on first interaction
  const handleFocus = async () => {
    if (existingEmps) return;
    setImporting(true);
    try { 
      await loadContext(); 
    } catch (err) { 
      console.error(err); 
    } finally {
      setImporting(false);
    }
  };

  // Uniqueness (Soft Match): Name fuzzy similarity > 90%
  const isSoftMatch = (row, existingRecord) => {
    const rowName = normalizeValue(row.full_name || row.name || '');
    const extName = normalizeValue(existingRecord.full_name);
    return calculateSimilarity(rowName, extName) > 0.90;
  };

  // Uniqueness (Hard Match): Exact Email OR Exact Phone OR (Name+Phone+Email > 85%)
  const isHardMatch = (row, existingRecord) => {
    const rowName = normalizeValue(row.full_name || row.name || '');
    const rowPhone = normalizeValue(row.phone || row.contactNumber || '');
    const rowEmail = row.email ? row.email.toLowerCase().trim() : '';

    const extName = normalizeValue(existingRecord.full_name);
    const extPhone = normalizeValue(existingRecord.phone);
    const extEmail = existingRecord.email ? existingRecord.email.toLowerCase().trim() : '';

    // Condition A: Emails match exactly (only if both are present)
    if (rowEmail && extEmail && rowEmail === extEmail) return true;

    // Condition B: Phones match exactly
    if (rowPhone && extPhone && rowPhone === extPhone) return true;

    // Condition C: Combined similarity > 85%
    const combinedRow = `${rowName}|${rowPhone}|${rowEmail}`;
    const combinedExt = `${extName}|${extPhone}|${extEmail}`;
    if (calculateSimilarity(combinedRow, combinedExt) > 0.85) return true;

    return false;
  };

  const renderConflictTile = (conflict) => (
    <div className="tile-content">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
        <h5 style={{ margin: 0, fontWeight: 600, color: 'var(--brand-green)' }}>
          {conflict.csvRow.full_name || conflict.csvRow.name}
        </h5>
        {conflict.matchMode === 'hard' && (
          <span style={{ fontSize: '0.6rem', padding: '2px 6px', background: 'rgba(255,68,68,0.1)', color: '#ff4444', borderRadius: '4px', textTransform: 'uppercase', fontWeight: 800 }}>
            Exact Match
          </span>
        )}
      </div>
      <p style={{ fontSize: '0.8rem', opacity: 0.7, margin: 0 }}>
        {conflict.csvRow.email}
      </p>
      <p style={{ fontSize: '0.8rem', opacity: 0.7, margin: 0 }}>
        {conflict.csvRow.phone || conflict.csvRow.contactNumber || 'No Phone'}
      </p>
    </div>
  );

  const handleDataParsed = async (rows) => {
    setImporting(true);
    try {
      const ctx = await loadContext();

      const parseDateForDB = (rawDate) => {
        if (!rawDate) return new Date().toISOString().split('T')[0];
        const parsed = new Date(rawDate);
        if (!isNaN(parsed.valueOf())) {
          // Extract local YYYY-MM-DD to avoid GMT offset string issues in Postgres
          const year = parsed.getFullYear();
          const month = String(parsed.getMonth() + 1).padStart(2, '0');
          const day = String(parsed.getDate()).padStart(2, '0');
          return `${year}-${month}-${day}`;
        }
        return new Date().toISOString().split('T')[0];
      };

      const empsToInsert = await Promise.all(rows.map(async (row) => {
        const name = row.full_name || row.name || '';
        if (!name.trim()) return null;

        const possibleMatches = ctx.existingEmps.filter(e => isHardMatch(row, e) || isSoftMatch(row, e));
        const existingMatch = possibleMatches.find(e => isHardMatch(row, e)) || possibleMatches[0];

        // Robust Lookup: Clean and normalize input
        const lookup = (val, map) => {
          if (!val) return null;
          return map[val.toString().toLowerCase().trim()] || null;
        };

        const role_id = lookup(row.role_code, ctx.roleMap);
        const department_id = lookup(row.dept_code, ctx.deptMap);
        const hire_date = parseDateForDB(row.hire_date);

        // ID & Badge Logic
        let emp_code = existingMatch?.emp_code;
        let badge_id = existingMatch?.badge_id;

        if (!emp_code) {
          emp_code = generateEmpCode();
        }

        // Re-calculate badge if new or role/dept changed
        if (!badge_id || (existingMatch && (existingMatch.role_id !== role_id || existingMatch.department_id !== department_id))) {
          badge_id = await calculateBadgeId({ role_id, department_id }, hire_date);
        }

        const mapped = {
          id: existingMatch?.id || (typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 11)),
          full_name: name.trim(),
          email: row.email || null,
          phone: row.phone || null,
          gender: row.gender || null,
          dob: parseDateForDB(row.dob),
          department_id,
          role_id,
          hub_id: lookup(row.hub_code || row.hub, ctx.hubMap),
          status: row.status || 'Active',
          hire_date,
          account_number: row.account_number || null,
          ifsc_code: row.ifsc_code || null,
          account_name: row.account_name || null,
          pan_number: row.pan_number || row.pan || null,
          emp_code,
          badge_id,
          updated_at: new Date().toISOString(),
        };

        return mapped;
      })).then(results => results.filter(Boolean));

      if (empsToInsert.length === 0) {
        throw new Error('No valid employee records found.');
      }

      const { error } = await supabase
        .from('employees')
        .upsert(empsToInsert, { onConflict: 'id' });

      if (error) throw error;

      // History Logging (Batch)
      for (const emp of empsToInsert) {
        await logEmployeeHistory(emp.id, emp, 'CSV_IMPORT');
      }

      alert(`Successfully processed ${empsToInsert.length} employees.`);
      setExistingEmps(null); // Reset for next import
      if (onImportComplete) onImportComplete();
    } catch (err) {
      console.error('Finalize Error:', err);
      alert(`Import failed: ${err.message || String(err)}`);
    } finally {
      setImporting(false);
    }
  };

  return (
    <CSVImportButton
      label={importing ? 'Importing...' : label}
      onDataParsed={handleDataParsed}
      requiredFields={['full_name']} // email is now optional
      getConflictKey={(row) => {
        const name = normalizeValue(row.full_name || row.name || '');
        const phone = normalizeValue(row.phone || row.contactNumber || '');
        const email = normalizeValue(row.email || '');
        return `${name}|${phone}|${email}` || 'new-row';
      }} 
      findConflict={(row, existingData) => {
        const hard = existingData.find(e => isHardMatch(row, e));
        if (hard) return { existingRecord: hard, matchMode: 'hard' };

        const soft = existingData.find(e => isSoftMatch(row, e));
        if (soft) return { existingRecord: soft, matchMode: 'soft' };

        return null;
      }}
      existingData={existingEmps}
      renderConflictTile={renderConflictTile}
      entityName="Employees"
      className={className}
      disabled={importing}
      compareFields={[
        { key: 'full_name', label: 'Name' },
        { key: 'email', label: 'Email' },
        { key: 'phone', label: 'Phone' },
        { key: 'gender', label: 'Gender' },
        { key: 'dob', label: 'D.O.B' },
        { key: 'hub_code', label: 'Hub' },
        { key: 'dept_code', label: 'Dept' },
        { key: 'role_code', label: 'Role' },
        { key: 'hire_date', label: 'D.O.J' }
      ]}
      onFocus={handleFocus}
    />
  );
};

export default EmployeeCSVImport;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import '../ChargingHubs/HubManagement.css'; // Use shared styles
import './EmployeeManagement.css';
import EmployeeCSVDownload from './EmployeeCSVDownload';
import EmployeeCSVImport from './EmployeeCSVImport';
import MasterPageHeader from '../../components/MasterPageHeader';
import TaskModal from '../../components/TaskModal';
import EmployeeForm from './EmployeeForm';
import EmployeeCard from './EmployeeCard';
import EmployeeListRow from './EmployeeListRow';
import { useEmployees } from '../../hooks/useEmployees';
import { matchesCriteria } from '../../utils/matchingAlgorithms';
import ConflictModal from '../../components/ConflictModal';

/**
 * EmployeeManagement
 * 
 * The primary view for the Employee Manager vertical.
 * Displays employee records, profiles, and administrative summaries.
 */
const EmployeeManagement = ({ permissions, filters }) => {
  const { employees, loading, fetchEmployees, addEmployee, updateEmployee, toggleStatus, deleteEmployee } = useEmployees();

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [viewMode, setViewMode] = useState(() => localStorage.getItem('powerpod_employee_view') || 'grid');
  const [showInactive, setShowInactive] = useState(true);
  const [editingEmployee, setEditingEmployee] = useState(null);
  const [isViewOnly, setIsViewOnly] = useState(false);
  const [pendingConflict, setPendingConflict] = useState(null); // { formData, existingRecord }

  useEffect(() => {
    fetchEmployees();
  }, [fetchEmployees]);

  useEffect(() => {
    localStorage.setItem('powerpod_employee_view', viewMode);
  }, [viewMode]);

  const handleSave = async (formData, force = false) => {
    if (!force) {
      // MASTER-SLAVE: Use master criteria logic
      // MASTER-SLAVE: Map form fields to match DB criteria
      const matchingProbe = {
        full_name: formData.name,
        phone: formData.contactNumber,
        email: formData.emailId
      };

      const existingMatch = employees.find(emp => 
        emp.id !== (editingEmployee?.id) && 
        matchesCriteria(matchingProbe, emp, { 
          fields: ['full_name'], 
          useFuzzy: true, 
          threshold: 0.85, 
          exactFields: ['phone'] 
        })
      );

      if (existingMatch) {
        setPendingConflict({ formData, existingRecord: existingMatch });
        return;
      }
    }

    setIsSaving(true);
    try {
      if (editingEmployee) {
        await updateEmployee(editingEmployee.id, formData);
      } else {
        await addEmployee(formData);
      }
      setIsAddModalOpen(false);
      setEditingEmployee(null);
    } catch (err) {
      console.error('EmployeeManagement: Operation Error:', err);
      alert(`Operation failed: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to permanently delete this employee record?")) {
      try {
        await deleteEmployee(id);
      } catch (err) {
        alert(`Delete failed: ${err.message}`);
      }
    }
  };

  const openEditModal = (emp) => {
    setEditingEmployee(emp);
    setIsViewOnly(false);
    setIsAddModalOpen(true);
  };

  const openViewModal = (emp) => {
    setEditingEmployee(emp);
    setIsViewOnly(true);
    setIsAddModalOpen(true);
  };

  const filteredEmployees = employees.filter(emp => {
    const matchesStatus = showInactive || emp.status === 'Active';

    // Apply Subsidebar Filters
    const matchesRole = !filters?.role?.length || filters.role.includes(emp.role_code);
    const matchesHub = !filters?.hub?.length || filters.hub.includes(emp.hub_id);
    const matchesDept = !filters?.department?.length || filters.department.includes(emp.dept_code);

    return matchesStatus && matchesRole && matchesHub && matchesDept;
  });

  const activeEmps = filteredEmployees.filter(emp => emp.status === 'Active');

  // Group active employees by role
  const activeEmpsByRole = activeEmps.reduce((acc, emp) => {
    // Prefix the key with seniority level (e.g. "09|Senior Developer") for easy sorting
    // We pad start with 0 so "10" sorts before "09" in a descending sort
    const roleName = emp.role_code || emp.role || 'Unassigned Role';
    const seniorityNum = typeof emp.seniority_level === 'number' ? emp.seniority_level : 1;
    const sortKey = `${String(seniorityNum).padStart(3, '0')}|${roleName}`;

    if (!acc[sortKey]) acc[sortKey] = { roleName, overrideKey: sortKey, emps: [] };
    acc[sortKey].emps.push(emp);
    return acc;
  }, {});

  const inactiveEmps = filteredEmployees.filter(emp => emp.status === 'Inactive');

  const isMasterAdmin = permissions?.roleId === 'master_admin';

  return (
    <>
      <MasterPageHeader
        title="Employee Records Manager"
        description="Centralized database for personnel profiles, performance tracking, and organizational assignments."
        leftActions={
          <>
            <div className="view-mode-toggle">
              {['grid', 'list'].map(mode => (
                <button 
                  key={mode}
                  className={`view-toggle-btn ${viewMode === mode ? 'active' : ''}`}
                  onClick={() => setViewMode(mode)}
                  title={`${mode.charAt(0).toUpperCase() + mode.slice(1)} View`}
                >
                  {mode.charAt(0).toUpperCase() + mode.slice(1)}
                </button>
              ))}
            </div>

            <button 
              className={`halo-button toggle-depri-btn ${!showInactive ? 'active' : ''}`}
              onClick={() => setShowInactive(!showInactive)}
              title={showInactive ? "Hide Inactive" : "Show Inactive"}
              style={{ fontWeight: 600, textDecoration: showInactive ? 'none' : 'line-through' }}
            >
              INACTIVE
            </button>
          </>
        }
        rightActions={
          <>
            <EmployeeCSVDownload className="master-action-btn" data={employees} label="Export Team" />
            <EmployeeCSVDownload className="master-action-btn" isTemplate label="Download Template" />
            <EmployeeCSVImport className="master-action-btn" label="Import Team" onImportComplete={fetchEmployees} />
            <button className="halo-button master-action-btn" onClick={() => { setEditingEmployee(null); setIsAddModalOpen(true); }}>
              + Add Employee
            </button>
          </>
        }
      />

      {loading ? (
        <div className="loading-spinner">Loading Employees...</div>
      ) : employees.length === 0 ? (
        <div className="empty-state" style={{ marginTop: '50px' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem', opacity: 0.5 }}>👥</div>
          <h3>Personnel Database Empty</h3>
          <p>Click "+ Add Employee" to insert your first structural record.</p>
        </div>
      ) : (
        <div style={{ marginTop: '1rem' }}>
          {/* ACTIVE SECTION */}
          <div className="status-section">
            <h4 className="section-title">Active Team ({activeEmps.length})</h4>
            {activeEmps.length === 0 ? (
              <p className="empty-sub-state">No active employees found matching filters.</p>
            ) : (
              <div className="grouped-employee-sections">
                {Object.values(activeEmpsByRole)
                  // Sort descending by overrideKey (seniority), then alphabetically by role name
                  .sort((a, b) => b.overrideKey.localeCompare(a.overrideKey))
                  .map(({ roleName, emps: empsInRole }) => (
                  <div key={roleName} className="role-group-section" style={{ marginBottom: '2.5rem' }}>
                    <h5 style={{ 
                      margin: '0 0 1rem 0', 
                      fontSize: '1rem', 
                      fontWeight: 600, 
                      color: 'var(--brand-green)', 
                      opacity: 0.9, 
                      borderBottom: '1px solid rgba(255,255,255,0.05)', 
                      paddingBottom: '0.5rem' 
                    }}>
                      {roleName} <span style={{ opacity: 0.5, fontSize: '0.8rem', marginLeft: '6px' }}>({empsInRole.length})</span>
                    </h5>
                    <div className={viewMode === 'grid' ? 'employee-grid' : 'employee-list'}>
                      {empsInRole.map(emp => (
                        viewMode === 'grid' ? (
                          <EmployeeCard 
                            key={emp.id} 
                            emp={emp} 
                            onEdit={openEditModal} 
                            onView={openViewModal}
                            onDelete={handleDelete} 
                            onToggleStatus={toggleStatus} 
                            isMasterAdmin={isMasterAdmin} 
                          />
                        ) : (
                          <EmployeeListRow 
                            key={emp.id} 
                            emp={emp} 
                            onEdit={openEditModal} 
                            onView={openViewModal}
                            onDelete={handleDelete} 
                            onToggleStatus={toggleStatus} 
                            isMasterAdmin={isMasterAdmin} 
                          />
                        )
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}

          </div>

          {/* INACTIVE SECTION */}
          {showInactive && (
            <div className="status-section inactive-section" style={{ marginTop: '3rem', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '2rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1.5rem' }}>
                <h4 className="section-title" style={{ margin: 0, opacity: 0.5 }}>Inactive / History ({inactiveEmps.length})</h4>
                <div style={{ height: '1px', flex: 1, background: 'rgba(255,255,255,0.05)' }}></div>
              </div>

              {inactiveEmps.length === 0 ? (
                <p className="empty-sub-state" style={{ opacity: 0.3 }}>No inactive records.</p>
              ) : (
                <div className={viewMode === 'grid' ? 'employee-grid' : 'employee-list'} style={{ opacity: 0.6 }}>
                  {inactiveEmps.map(emp => (
                    viewMode === 'grid' ? (
                      <EmployeeCard 
                        key={emp.id} 
                        emp={emp} 
                        onEdit={openEditModal} 
                        onView={openViewModal}
                        onDelete={handleDelete} 
                        onToggleStatus={toggleStatus} 
                        isMasterAdmin={isMasterAdmin} 
                      />
                    ) : (
                      <EmployeeListRow 
                        key={emp.id} 
                        emp={emp} 
                        onEdit={openEditModal} 
                        onView={openViewModal}
                        onDelete={handleDelete} 
                        onToggleStatus={toggleStatus} 
                        isMasterAdmin={isMasterAdmin} 
                      />
                    )
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      <TaskModal
        isOpen={isAddModalOpen}
        onClose={() => { setIsAddModalOpen(false); setEditingEmployee(null); setIsViewOnly(false); }}
        title={isViewOnly ? "View Employee Record" : (editingEmployee ? "Edit Employee Record" : "Add New Employee Record")}
        className="large-modal"
      >
        <EmployeeForm 
          onSubmit={handleSave} 
          isViewOnly={isViewOnly}
          initialData={editingEmployee ? {
            id: editingEmployee.id,
            name: editingEmployee.full_name,
            contactNumber: editingEmployee.phone,
            emailId: editingEmployee.email,
            gender: editingEmployee.gender,
            dob: editingEmployee.dob,
            doj: editingEmployee.hire_date,
            hub_id: editingEmployee.hub_id,
            role_id: editingEmployee.role_id,
            department_id: editingEmployee.department_id,
            accountNumber: editingEmployee.account_number,
            ifscCode: editingEmployee.ifsc_code,
            accountName: editingEmployee.account_name,
            panNumber: editingEmployee.pan_number,
            emp_code: editingEmployee.emp_code,
            badge_id: editingEmployee.badge_id
          } : {}}
          loading={isSaving} 
        />
      </TaskModal>

      {/* Unified Conflict Resolution Modal */}
      <ConflictModal
        isOpen={!!pendingConflict}
        onClose={() => setPendingConflict(null)}
        title="Potential Duplicate Detected"
        description="We found a similar employee record in the database. Are you sure you want to create a new entry or update the existing one?"
        conflicts={pendingConflict ? [pendingConflict.existingRecord] : []}
        strategy="REPLACE_ALL_OR_SELECT"
        entityName="Employees"
        onResolve={() => {
          const data = pendingConflict.formData;
          setPendingConflict(null);
          handleSave(data, true); // Force save
        }}
        renderConflictTile={(emp) => (
          <div className="conflict-emp-tile">
            <h5 style={{ color: 'var(--brand-green)', margin: '0 0 4px 0' }}>{emp.full_name}</h5>
            <p style={{ fontSize: '0.8rem', opacity: 0.7 }}>{emp.email || 'No Email'}</p>
            <p style={{ fontSize: '0.8rem', opacity: 0.7 }}>{emp.phone || 'No Phone'}</p>
          </div>
        )}
      />
    </>
  );
};

export default EmployeeManagement;

