import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';
import './EmployeeRoleManagement.css';
import '../ChargingHubs/HubManagement.css'; // Global grid/list layout logic
import MasterPageHeader from '../../components/MasterPageHeader';

const EmployeeRoleManagement = () => {
  const [roles, setRoles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRole, setEditingRole] = useState(null);
  const [formData, setFormData] = useState({ name: '', role_code: '', description: '', seniority_level: 1 });
  const [statusMsg, setStatusMsg] = useState({ type: '', text: '' });
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchRoles();
  }, []);

  const fetchRoles = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('employee_roles')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error('Error fetching employee roles:', error);
    } else {
      setRoles(data || []);
    }
    setLoading(false);
  };

  const handleOpenModal = (role = null) => {
    if (role) {
      setEditingRole(role);
      setFormData({ 
        name: role.name, 
        role_code: role.role_code || '',
        description: role.description || '',
        seniority_level: role.seniority_level || 1
      });
    } else {
      setEditingRole(null);
      setFormData({ name: '', role_code: '', description: '', seniority_level: 1 });
    }
    setIsModalOpen(true);
    setStatusMsg({ type: '', text: '' });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatusMsg({ type: '', text: '' });

    const roleData = {
      ...formData,
      updated_at: new Date().toISOString()
    };

    let error;
    if (editingRole) {
      const { error: updateError } = await supabase
        .from('employee_roles')
        .update(roleData)
        .eq('id', editingRole.id);
      error = updateError;
    } else {
      const { error: insertError } = await supabase
        .from('employee_roles')
        .insert([roleData]);
      error = insertError;
    }

    if (error) {
      setStatusMsg({ type: 'error', text: `Error: ${error.message}` });
    } else {
      setStatusMsg({ type: 'success', text: `Role ${editingRole ? 'updated' : 'created'} successfully!` });
      setTimeout(() => {
        setIsModalOpen(false);
        fetchRoles();
      }, 1000);
    }
    setLoading(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this role?')) return;

    setLoading(true);
    const { error } = await supabase.from('employee_roles').delete().eq('id', id);

    if (error) {
      alert(`Delete failed: ${error.message}`);
    } else {
      fetchRoles();
    }
    setLoading(false);
  };

  return (
    <div className="management-view-container">
      <MasterPageHeader
        title="Employee Role Management"
        description="Define and manage specific job roles for the employee vertical."
        leftActions={
          <div className="view-mode-toggle">
            <button 
              className={`view-toggle-btn ${viewMode === 'grid' ? 'active' : ''}`}
              onClick={() => setViewMode('grid')}
            >
              Grid
            </button>
            <button 
              className={`view-toggle-btn ${viewMode === 'list' ? 'active' : ''}`}
              onClick={() => setViewMode('list')}
            >
              List
            </button>
          </div>
        }
        rightActions={
          <button className="halo-button master-action-btn" onClick={() => handleOpenModal()}>
            + New Role
          </button>
        }
      />

      {loading && !isModalOpen && <div className="loading-spinner">Loading Roles...</div>}

      {viewMode === 'grid' ? (
        <div className="hubs-grid">
          {roles.map(role => (
            <div key={role.id} className="hub-card">
              <div className="hub-code-tag">{role.role_code || 'NO CODE'}</div>
              <div className="seniority-tag">Level {role.seniority_level || 1}</div>
              <h3>{role.name}</h3>
              <p className="hub-city">{role.description || 'No description provided'}</p>
              <div className="hub-actions">
                <button className="halo-button edit-btn" onClick={() => handleOpenModal(role)}>Edit</button>
                <button className="halo-button delete-btn" onClick={() => handleDelete(role.id)}>Delete</button>
              </div>
            </div>
          ))}
          {roles.length === 0 && !loading && (
            <div className="empty-state">
              <p>No roles found. Create your first employee role to get started!</p>
            </div>
          )}
        </div>
      ) : (
        <div className="hubs-list-view">
          <table className="management-table">
            <thead>
              <tr>
                <th>Role Name</th>
                <th>Code</th>
                <th>Seniority</th>
                <th>Description</th>
                <th style={{ textAlign: 'right' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {roles.map(role => (
                <tr key={role.id}>
                  <td className="name-cell">{role.name}</td>
                  <td><code className="code-font">{role.role_code || '—'}</code></td>
                  <td>
                    <span className="seniority-tag">Level {role.seniority_level || 1}</span>
                  </td>
                  <td style={{ opacity: 0.7, fontSize: '0.85rem' }}>{role.description || '—'}</td>
                  <td style={{ textAlign: 'right' }}>
                    <div className="table-actions">
                      <button className="icon-btn edit" onClick={() => handleOpenModal(role)} title="Edit">✎</button>
                      <button className="icon-btn delete" onClick={() => handleDelete(role.id)} title="Delete">×</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {roles.length === 0 && !loading && (
            <div className="empty-state">
              <p>No roles found.</p>
            </div>
          )}
        </div>
      )}

      {isModalOpen && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="modal-content hub-modal" onClick={(e) => e.stopPropagation()}>
            <header className="modal-header">
              <h2>{editingRole ? 'Edit Role' : 'Create New Role'}</h2>
              <button className="close-modal" onClick={() => setIsModalOpen(false)}>&times;</button>
            </header>

            <form onSubmit={handleSubmit} className="vertical-task-form">
              <div className="form-row-grid">
                <div className="form-group">
                  <label>Role Name</label>
                  <input 
                    type="text" 
                    value={formData.name} 
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    placeholder="e.g. Senior Developer, Marketing Associate"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Role Code</label>
                  <input 
                    type="text" 
                    value={formData.role_code} 
                    onChange={(e) => setFormData({...formData, role_code: e.target.value})}
                    placeholder="e.g. SR-DEV, MKT-ASC"
                  />
                </div>

                <div className="form-group">
                  <label>Seniority Level</label>
                  <input 
                    type="number" 
                    min="1" 
                    max="10"
                    value={formData.seniority_level} 
                    onChange={(e) => setFormData({...formData, seniority_level: parseInt(e.target.value) || 1})}
                    placeholder="1-10 (1=lowest, 10=highest)"
                    required
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea 
                  value={formData.description} 
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="What are the key responsibilities of this role?"
                  rows={4}
                />
              </div>

              {statusMsg.text && (
                <div className={`status-message ${statusMsg.type}`}>
                  {statusMsg.text}
                </div>
              )}

              <div className="modal-footer">
                <button type="button" className="halo-button cancel-btn" onClick={() => setIsModalOpen(false)}>Cancel</button>
                <button type="submit" className="halo-button save-btn" disabled={loading}>
                  {loading ? 'Saving...' : (editingRole ? 'Update' : 'Create')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeRoleManagement;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabaseClient';

/**
 * EmployeeSubSidebar
 * 
 * Vertical-specific sidebar content for the Employee Manager.
 * Contains filters for employee records.
 */
const EmployeeSubSidebar = ({ user, permissions, activeVertical, setActiveVertical, onFilterChange, onReset, onBatchFilter, filters, tasks }) => {
  const canAccessAdmin = permissions?.canAccessConfig;

  const [expandedGroups, setExpandedGroups] = useState({
    role: false,
    hub: false,
    department: false,
  });

  const [filterOptions, setFilterOptions] = useState({
    hubs: [],
    roles: [],
    departments: []
  });

  useEffect(() => {
    const fetchOptions = async () => {
      const [{ data: hubs }, { data: roles }, { data: depts }] = await Promise.all([
        supabase.from('hubs').select('id, name, hub_code').order('name'),
        supabase.from('employee_roles').select('name, role_code').order('name'),
        supabase.from('departments').select('name, dept_code').order('name')
      ]);

      setFilterOptions({
        hubs: hubs || [],
        roles: roles || [],
        departments: depts || []
      });
    };
    fetchOptions();
  }, []);

  const toggleGroup = (key) => {
    setExpandedGroups(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const filterSectionStyle = {
    borderBottom: '1px solid var(--border-color)',
    transition: 'all 0.3s ease'
  };

  const groupHeaderStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '12px',
    cursor: 'pointer',
    userSelect: 'none'
  };

  const groupLabelStyle = {
    fontSize: '0.75rem',
    fontWeight: 600,
    textTransform: 'uppercase',
    color: 'var(--brand-green)',
    letterSpacing: '0.5px'
  };

  const checkboxGroupStyle = (isExpanded) => ({
    display: isExpanded ? 'flex' : 'none',
    flexDirection: 'column',
    gap: '8px',
    maxHeight: '180px',
    overflowY: 'auto',
    padding: '0 12px 16px 12px',
    transition: 'opacity 0.2s ease'
  });

  const checkboxItemStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    cursor: 'pointer',
    fontSize: '0.85rem',
    color: 'var(--text-color)',
    padding: '4px 0',
    opacity: 0.8
  };

  const checkMarkStyle = (isSelected) => ({
    width: '16px',
    height: '16px',
    borderRadius: '4px',
    border: '2px solid var(--border-color)',
    backgroundColor: isSelected ? 'var(--brand-green)' : 'transparent',
    borderColor: isSelected ? 'var(--brand-green)' : 'var(--border-color)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '10px',
    color: 'white',
    transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)'
  });

  const FilterGroup = ({ label, options, currentFilters, filterKey, displayKey, valueKey }) => {
    const isExpanded = expandedGroups[filterKey];
    return (
      <div style={filterSectionStyle}>
        <div style={groupHeaderStyle} onClick={() => toggleGroup(filterKey)}>
          <span style={groupLabelStyle}>{label}</span>
          <span style={{ fontSize: '0.7rem', opacity: 0.5 }}>{isExpanded ? '▲' : '▼'}</span>
        </div>

        {isExpanded && (
          <div style={{ padding: '0 12px 8px 12px', display: 'flex', gap: '12px' }}>
            <button
              onClick={(e) => {
                e.stopPropagation();
                const allVals = options.map(opt => valueKey ? opt[valueKey] : opt);
                onBatchFilter(filterKey, allVals);
              }}
              style={{ fontSize: '0.65rem', fontWeight: 600, color: 'var(--brand-green)', background: 'none', border: 'none', padding: 0, cursor: 'pointer', opacity: 0.8 }}
            >
              SELECT ALL
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onBatchFilter(filterKey, []);
              }}
              style={{ fontSize: '0.65rem', fontWeight: 600, color: '#ef4444', background: 'none', border: 'none', padding: 0, cursor: 'pointer', opacity: 0.8 }}
            >
              CLEAR
            </button>
          </div>
        )}

        <div style={checkboxGroupStyle(isExpanded)} className="custom-scrollbar">
          {options.map(opt => {
            const val = valueKey ? opt[valueKey] : opt;
            const labelText = displayKey ? opt[displayKey] : opt;
            const isSelected = (currentFilters || []).includes(val);
            return (
              <div
                key={val}
                style={{ ...checkboxItemStyle, opacity: isSelected ? 1 : 0.6 }}
                onClick={() => onFilterChange(filterKey, val)}
              >
                <div style={checkMarkStyle(isSelected)}>
                  {isSelected && '✓'}
                </div>
                <span style={{ fontWeight: isSelected ? 600 : 400 }}>{labelText}</span>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="sub-sidebar-body">
      {/* Admin Quick Links */}
      {canAccessAdmin && (
        <div style={{ padding: '12px', marginBottom: '8px', display: 'flex', flexDirection: 'column', gap: '8px' }}>
          <button
            className="halo-button"
            style={{ width: '100%', opacity: activeVertical === 'employee_tasks' ? 1 : 0.7 }}
            onClick={() => setActiveVertical('employee_tasks')}
          >
            Employee Tasks
          </button>
          <button
            className="halo-button"
            style={{ width: '100%', opacity: activeVertical === 'department_management' ? 1 : 0.7 }}
            onClick={() => setActiveVertical('department_management')}
          >
            Department Manager
          </button>
        </div>
      )}

      {/* Filters Header */}
      <div style={{ padding: '16px 12px 8px 12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid var(--border-color)' }}>
        <p style={{ margin: 0, fontWeight: 700, fontSize: '1rem', color: 'var(--text-color)', letterSpacing: '0.5px' }}>Employees</p>
        <button
          onClick={onReset}
          style={{
            background: 'none',
            border: 'none',
            color: 'var(--brand-green)',
            fontSize: '0.7rem',
            fontWeight: 800,
            cursor: 'pointer',
            padding: '4px'
          }}
        >
          RESET
        </button>
      </div>

      <div style={{ padding: '8px 12px', backgroundColor: 'rgba(255,255,255,0.03)', borderBottom: '1px solid var(--border-color)' }}>
        <p style={{ margin: 0, fontSize: '0.7rem', fontWeight: 600, opacity: 0.5, textTransform: 'uppercase' }}>Filter Records</p>
      </div>

      <FilterGroup
        label="Employee Role"
        options={filterOptions.roles}
        currentFilters={filters.role}
        filterKey="role"
        displayKey="role_code"
        valueKey="role_code"
      />

      <FilterGroup
        label="Primary Hub"
        options={filterOptions.hubs}
        currentFilters={filters.hub}
        filterKey="hub"
        displayKey="hub_code"
        valueKey="id"
      />

      <FilterGroup
        label="Department"
        options={filterOptions.departments}
        currentFilters={filters.department}
        filterKey="department"
        displayKey="dept_code"
        valueKey="dept_code"
      />

      <div className="sub-nav-item" style={{ marginTop: '24px', opacity: 0.4 }}>
        <div className="sub-nav-text">
          <p>Employee Manager</p>
          <small>Task Board Active</small>
        </div>
      </div>
    </div>
  );
};

export default EmployeeSubSidebar;

